                    f.write(line)

            return redirect(url_for('auction_details', auction_id=auction_id))

        # If errors, render with errors
        return render_template('place_bid.html', auction_name=auction_name, minimum_bid=minimum_bid, bidder_name=bidder_name, bid_amount=bid_amount, errors=errors)

